const source = $input.first()?.json ?? {};
const query = source.query ?? source;
const clean = (value) => value === null || value === undefined ? '' : String(value).trim();
const escapeHtml = (value) => clean(value)
  .replace(/&/g, '&amp;')
  .replace(/</g, '&lt;')
  .replace(/>/g, '&gt;')
  .replace(/"/g, '&quot;')
  .replace(/'/g, '&#39;');
const member = clean(query.member);
const batchId = clean(query.batch_id ?? query.batchId);
const actionUrl = 'http://n8n:5678/webhook/add-manual-batch-item';
const html = `<!doctype html>
<html lang="en">
<head>
  <meta charset="utf-8">
  <meta name="viewport" content="width=device-width, initial-scale=1">
  <title>Manual Batch Item</title>
  <style>
    :root {
      color-scheme: light;
      --bg: #f5f7f3;
      --panel: #ffffff;
      --ink: #183321;
      --muted: #567061;
      --line: #cfdacd;
      --accent: #2f7d45;
    }
    * { box-sizing: border-box; }
    body {
      margin: 0;
      font-family: Georgia, 'Times New Roman', serif;
      color: var(--ink);
      background: linear-gradient(180deg, #eef4ea 0%, var(--bg) 100%);
      min-height: 100vh;
      padding: 24px;
    }
    .wrap {
      max-width: 760px;
      margin: 0 auto;
      background: var(--panel);
      border: 1px solid var(--line);
      border-radius: 18px;
      padding: 28px;
      box-shadow: 0 18px 40px rgba(24, 51, 33, 0.08);
    }
    h1 {
      margin: 0 0 8px;
      font-size: 30px;
      line-height: 1.1;
    }
    .lede {
      margin: 0 0 20px;
      color: var(--muted);
      font-size: 16px;
    }
    .member {
      margin: 0 0 22px;
      padding: 14px 16px;
      background: #f6faee;
      border: 1px solid #dbe8c0;
      border-radius: 12px;
    }
    .member strong {
      display: block;
      font-size: 20px;
      margin-bottom: 4px;
    }
    form {
      display: grid;
      gap: 16px;
    }
    .grid {
      display: grid;
      gap: 16px;
      grid-template-columns: repeat(auto-fit, minmax(180px, 1fr));
    }
    label {
      display: block;
      font-weight: 600;
      margin-bottom: 6px;
    }
    input, textarea {
      width: 100%;
      border: 1px solid var(--line);
      border-radius: 10px;
      padding: 10px 12px;
      font: inherit;
      color: var(--ink);
      background: #fff;
    }
    input[type="number"] {
      text-align: center;
    }
    textarea {
      min-height: 110px;
      resize: vertical;
    }
    .help {
      margin-top: 4px;
      color: var(--muted);
      font-size: 13px;
    }
    .actions {
      display: flex;
      gap: 12px;
      align-items: center;
      flex-wrap: wrap;
      margin-top: 4px;
    }
    button {
      appearance: none;
      border: 0;
      border-radius: 999px;
      padding: 12px 18px;
      font: inherit;
      font-weight: 700;
      color: white;
      background: linear-gradient(135deg, var(--accent) 0%, #1d6132 100%);
      cursor: pointer;
    }
    .note {
      color: var(--muted);
      font-size: 14px;
    }
    .warning {
      margin-top: 18px;
      padding-top: 14px;
      border-top: 1px dashed var(--line);
      color: var(--muted);
      font-size: 14px;
    }
  </style>
</head>
<body>
  <div class="wrap">
    <h1>Manual Batch Item</h1>
    <p class="lede">Add shoe tags, parent tags, or keys without creating a fake signup row.</p>
    <div class="member">
      <strong>${escapeHtml(member || 'Unknown member')}</strong>
      <span>The add-manual flow currently matches by member name.</span>
    </div>
    <form action="${actionUrl}" method="get" target="_blank">
      <input type="hidden" name="member" value="${escapeHtml(member)}">
      <input type="hidden" name="created_by" value="metabase_manual_batch_form">
      <div>
        <label for="batch_id">Batch ID</label>
        <input id="batch_id" name="batch_id" type="number" min="1" step="1" value="${escapeHtml(batchId)}">
        <div class="help">Leave blank to use the latest <code>Processing</code> batch.</div>
      </div>
      <div class="grid">
        <div>
          <label for="regular_tags">Shoe Tags</label>
          <input id="regular_tags" name="regular_tags" type="number" min="0" step="1" value="0">
        </div>
        <div>
          <label for="parent_tags">Parent Tags</label>
          <input id="parent_tags" name="parent_tags" type="number" min="0" step="1" value="0">
        </div>
        <div>
          <label for="key_tags">Keys</label>
          <input id="key_tags" name="key_tags" type="number" min="0" step="1" value="0">
        </div>
      </div>
      <div>
        <label for="notes">Notes</label>
        <textarea id="notes" name="notes" placeholder="Reason or context for the manual batch item"></textarea>
      </div>
      <div class="actions">
        <button type="submit">Add Manual Batch Item</button>
        <span class="note">The result opens in a new tab as JSON from the add-manual-item webhook.</span>
      </div>
    </form>
    <div class="warning">Use this only for genuine manual additions. Real signups should still come through the normal email capture path.</div>
  </div>
</body>
</html>`;
return [{ json: { html } }];

